'use client'

import { motion } from 'motion/react'
import { ReactNode } from 'react'

/**
 * Bento layout for the "Everything you need" feature grid.
 *
 * Each card pairs a real product screenshot CROP (pre-generated by
 * scripts/crop-screenshots.py — pixel-perfect regions of the live
 * app) with a short title + description. Crops are bordered only by
 * the dark-screenshot edge itself, no chunky white frame, with a
 * subtle violet shadow underneath.
 */
export function BentoGrid({ children, className = '' }: { children: ReactNode; className?: string }) {
  return (
    <div className={`grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-4 ${className}`}>
      {children}
    </div>
  )
}

export function BentoCard({
  title,
  description,
  icon,
  className = '',
  visual,
  delay = 0,
}: {
  title: string
  description: string
  icon: ReactNode
  className?: string
  visual?: ReactNode
  delay?: number
}) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, amount: 0.3 }}
      // Single transition prop covers both the entry stagger AND the
      // hover lift. Custom ease per emil-design-eng's curve.
      transition={{
        duration: 0.6,
        delay,
        ease: [0.23, 1, 0.32, 1],
      }}
      whileHover={{ y: -6, boxShadow: '0 30px 60px -20px rgba(124,58,237,0.32)' }}
      // Light mode: clean white card on lavender-tinted bg.
      // Dark mode: translucent glass with backdrop blur (Aurora +
      // meteors show through). Hover brightens the ring + border.
      // focus-within ring for keyboard nav into card-internal links.
      className={`group relative overflow-hidden rounded-2xl bg-card border border-border hover:border-brand/60 focus-within:ring-2 focus-within:ring-brand/40 transition-[border-color,transform] duration-300 flex flex-col shadow-[0_10px_40px_-20px_rgba(76,29,149,0.18)] dark:bg-white/[0.04] dark:backdrop-blur-md dark:border-white/10 dark:hover:border-brand/50 dark:shadow-[0_10px_40px_-20px_rgba(0,0,0,0.4)] ${className}`}
    >
      {/* Soft violet/cyan hover wash */}
      <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none bg-gradient-to-br from-brand/10 via-transparent to-brand-2/10" />

      {visual && <div className="relative px-5 pt-5 pb-3">{visual}</div>}

      <div className="relative px-5 pb-5 pt-3 flex-1">
        <div className="flex items-center gap-2.5 mb-2">
          <div className="w-7 h-7 rounded-md bg-brand/15 border border-brand/30 flex items-center justify-center text-brand">
            {icon}
          </div>
          <h3 className="text-sm font-semibold text-foreground tracking-tight">{title}</h3>
        </div>
        <p className="text-[13px] text-muted-foreground leading-relaxed">{description}</p>
      </div>
    </motion.div>
  )
}

// ─────────────── visuals — pre-cropped real screenshots ───────────────

/**
 * Renders a pre-cropped screenshot. No border, just a rounded clip
 * and a soft violet-tinted shadow. Hover scales subtly (in addition
 * to the parent card lifting).
 *
 * `position` is the CSS object-position (e.g. 'top', 'left top') —
 * only matters when the displayed aspect ratio is tighter than the
 * source's, in which case object-cover trims along the configured
 * axis. Defaults to 'top' so we always show the meaningful header
 * region first.
 */
function CropImage({
  src,
  alt,
  position = 'top',
  className = '',
}: {
  src: string
  alt: string
  position?: string
  className?: string
}) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.97 }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true, amount: 0.3 }}
      transition={{ duration: 0.5, ease: 'easeOut' }}
      className={`relative rounded-xl overflow-hidden shadow-[0_18px_45px_-18px_rgba(76,29,149,0.30),0_8px_24px_-12px_rgba(0,0,0,0.20)] ${className}`}
    >
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={src}
        alt={alt}
        // object-contain guarantees no cropping — full image always
        // visible. With aspect-[X/Y] matching the source dims, the
        // image fills the container with no letterbox. If browsers
        // round dims down by a fraction, contain falls back to a
        // tiny letterbox in the bg color rather than clipping pixels.
        className="block w-full h-full object-contain"
        style={{ objectPosition: position }}
      />
    </motion.div>
  )
}

